VALUES
  ('social-worker-moex-03250', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關佛洛伊德（S.Freud）本我（id）、自我（ego）、超我（superego）及其關係的敘述，下列何者錯誤？', '["本我構成了人類的基本需求和驅力，它可以經由我們主觀意識所覺察", "自我受現實原則所操控，是屬於心理狀態的理性方面", "超我來自社會文化的行為規範和道德期待", "自我是本我和超我的中介協調機制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03251', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '將一杯水倒入另個較高、較窄的玻璃杯中，幼兒以為較高、較窄玻璃杯容量比原先的杯子大。這 種思考特徵，是屬於皮亞傑（J.Piaget）認知發展論中的那一個階段？', '["感覺動作期（sensorimotorstage）", "前運思期（preoperationalstage）", "具體運思期（concreteoperationalstage）", "形式運思期（formaloperationalstage）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03252', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對郭爾堡（L.Kohlberg）道德發展理論的整體評述，何者最為正確？', '["此論主張道德發展從兒童時期就開始進行，人人都可以發展到第三個層次", "此論重視個體日常生活中實際的道德行為，而非道德推理的過程", "此論透過核心品格的分類和增進道德素養情境的設計，提高個體道德的發展", "此論從個人主義出發，無法適用某些重視社群或彼此關係的情境，有文化偏誤的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03253', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關ABC-X家庭壓力模式中的壓力事件A，下列敘述何者正確？', '["家庭壓力事件為累積的壓力，之前的壓力事件還未處理好，又加上新的壓力事件", "通常可預期的家庭壓力事件所帶來的改變和衝擊對家庭的影響較大", "家庭壓力事件指包括各種影響家庭界限、角色、價值觀或發展過程等任何正向、負向改變", "通常家庭對該壓力事件的看法，以及家庭成員是否能有共識，會影響對家庭產生的壓力程度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03254', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據Duvall（1977）的家庭生命週期八階段，其一階段的家庭發展任務為「協助年輕人在工作、結 婚等生活上適應得更好，使家庭成為家庭成員間重要的支持來源」，下列那個階段最符合以上敘述？', '["無子女的新婚伴侶階段", "養育學齡子女階段", "子女將離家階段", "伴侶進入空巢期與退休階段"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03255', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在家庭生命週期理論中，下列何者不是老年家庭（伴侶雙方退休至死亡）階段的發展任務？', '["適應及接受老化", "接受及適應成為祖父母的角色", "適應及接受退休，並能維持穩定及有品質的生活", "適應喪偶及獨居生活"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03256', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「親密關係暴力中，受暴者難以離開施暴者，可能是因性別權力差異」，此說法是基於什麼樣的理 論主張？', '["衝突理論", "功能論", "符號互動論", "系統理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03257', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '再婚家庭的發展核心任務包括：①處理自己失落的婚姻與哀傷  ②協助孩子與新舊任配偶適應新', '["與新配偶關係的確定，接受不同的家庭模式", "協調多重新的角色和界限問題。下列 組合何者正確？", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
