  ('social-worker-moex-03259', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依Parten對兒童遊戲的描述，下列何者正確？', '["遊戲可以協助兒童發展想像力", "兒童獨自玩遊戲通常代表同儕關係不好", "兒童聯合遊戲（associativeplay）一定要有共同組織與目標", "兒童在同儕遊戲中，只是旁觀但不參與，顯示有社交恐懼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
